<template><section class="manager"><div class="manager__head"><div><span>MONITORAMENTO</span><h2>Compras com afiliados</h2></div><q-btn flat round icon="mdi-refresh" :loading="loading" @click="load" /></div><q-table flat bordered class="manager__table" row-key="_id" :rows="rows" :columns="columns" :loading="loading"><template #body-cell-user="p"><q-td :props="p"><strong>{{p.row.user?.name||'-'}}</strong><small>{{p.row.user?.email||'-'}}</small></q-td></template><template #body-cell-course="p"><q-td :props="p">{{p.row.course?.title||'-'}}</q-td></template><template #body-cell-affiliate="p"><q-td :props="p">{{p.row.affiliate?.name||'-'}}<small>{{p.row.couponCode||'Sem cupom'}}</small></q-td></template><template #body-cell-paidAt="p"><q-td :props="p">{{p.row.paidAt?new Date(p.row.paidAt).toLocaleString('pt-BR'):'-'}}</q-td></template></q-table></section></template>
<script setup>import {onMounted,ref} from 'vue';import{api}from'boot/axios';const token=localStorage.getItem('aito_admin_token');const headers={headers:{Authorization:`Bearer ${token}`}};const rows=ref([]);const loading=ref(false);const columns=[{name:'user',label:'Usuário',field:'user',align:'left'},{name:'course',label:'Curso',field:'course',align:'left'},{name:'affiliate',label:'Afiliado / cupom',field:'affiliate',align:'left'},{name:'paidAmount',label:'Pago',field:'paidAmount',align:'right'},{name:'commissionAmount',label:'Comissão',field:'commissionAmount',align:'right'},{name:'paidAt',label:'Pagamento',field:'paidAt',align:'left'}];async function load(){loading.value=true;try{rows.value=(await api.get('/admin/affiliate-purchases',headers)).data.data||[]}finally{loading.value=false}}onMounted(load)</script><style scoped>.manager{color:#effffb}.manager__head{display:flex;align-items:center;justify-content:space-between}.manager__head span{color:#8fffee;font-size:.68rem;font-weight:800;letter-spacing:.14em}.manager h2{margin:.3rem 0 1rem}.manager__table{background:rgba(4,24,25,.72);color:#effffb}.manager__table small{display:block;color:rgba(239,255,251,.58);font-size:.68rem}</style>
